```java
package com.example.cache;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import java.util.*;

/**
 * A thread-safe LRU (Least Recently Used) cache implementation.
 * This cache maintains access order and automatically evicts the least recently used entry
 * when the capacity is reached.
 *
 * @param <K> the type of keys maintained by this cache
 * @param <V> the type of mapped values
 */
public class LRUCache<K, V> {
    private final int capacity;
    private final ConcurrentHashMap<K, Node<K, V>> map;
    private final DoublyLinkedList<K, V> lruList;
    private final ReentrantReadWriteLock lock;
    private final ReentrantReadWriteLock.ReadLock readLock;
    private final ReentrantReadWriteLock.WriteLock writeLock;

    public LRUCache(int capacity) {
        if (capacity <= 0) {
            throw new IllegalArgumentException("Capacity must be positive: " + capacity);
        }
        this.capacity = capacity;
        this.map = new ConcurrentHashMap<>(capacity);
        this.lruList = new DoublyLinkedList<>();
        this.lock = new ReentrantReadWriteLock();
        this.readLock = lock.readLock();
        this.writeLock = lock.writeLock();
    }

    public V get(K key) {
        if (key == null) {
            throw new IllegalArgumentException("Key cannot be null");
        }
        readLock.lock();
        try {
            Node<K, V> node = map.get(key);
            if (node == null) {
                return null;
            }
            lruList.moveToHead(node);
            return node.value;
        } finally {
            readLock.unlock();
        }
    }

    public void put(K key, V value) {
        if (key == null) {
            throw new IllegalArgumentException("Key cannot be null");
        }
        if (value == null) {
            throw new IllegalArgumentException("Value cannot be null");
        }
        writeLock.lock();
        try {
            Node<K, V> existing = map.get(key);
            if (existing != null) {
                existing.value = value;
                lruList.moveToHead(existing);
                return;
            }
            if (map.size() >= capacity) {
                Node<K, V> tail = lruList.removeTail();
                if (tail != null) {
                    map.remove(tail.key);
                }
            }
            Node<K, V> newNode = new Node<>(key, value);
            lruList.addToHead(newNode);
            map.put(key, newNode);
        } finally {
            writeLock.unlock();
        }
    }

    public int size() {
        readLock.lock();
        try {
            return map.size();
        } finally {
            readLock.unlock();
        }
    }

    public void clear() {
        writeLock.lock();
        try {
            map.clear();
            lruList.clear();
        } finally {
            writeLock.unlock();
        }
    }

    private static class Node<K, V> {
        K key;
        V value;
        Node<K, V> prev;
        Node<K, V> next;

        Node(K key, V value) {
            this.key = key;
            this.value = value;
        }
    }

    private static class DoublyLinkedList<K, V> {
        private Node<K, V> head;
        private Node<K, V> tail;

        void addToHead(Node<K, V> node) {
            if (head == null) {
                head = tail = node;
            } else {
                node.next = head;
                head.prev = node;
                head = node;
            }
        }

        void moveToHead(Node<K, V> node) {
            if (node == head) return;
            if (node == tail) {
                tail = tail.prev;
                if (tail != null) tail.next = null;
            } else {
                node.prev.next = node.next;
                node.next.prev = node.prev;
            }
            node.prev = null;
            node.next = head;
            if (head != null) head.prev = node;
            head = node;
            if (tail == null) tail = head;
        }

        Node<K, V> removeTail() {
            if (tail == null) return null;
            Node<K, V> removed = tail;
            tail = tail.prev;
            if (tail != null) tail.next = null;
            else head = null;
            removed.prev = removed.next = null;
            return removed;
        }

        void clear() {
            head = tail = null;
        }
    }
}
